-- PJAZZA Malta Retail Directory — 50+ real Malta businesses
-- Pre-populated for "claim your listing" flow. owner_id NULL = unclaimed.
-- Self-contained: adds missing columns if migrations 004/005 were skipped.

-- Ensure businesses has required columns
ALTER TABLE public.businesses
  ADD COLUMN IF NOT EXISTS logo_url TEXT,
  ADD COLUMN IF NOT EXISTS image_urls TEXT[] DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS google_review_count INT DEFAULT 0,
  ADD COLUMN IF NOT EXISTS google_rating DECIMAL(2,1) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS tripadvisor_review_count INT DEFAULT 0,
  ADD COLUMN IF NOT EXISTS tripadvisor_rating DECIMAL(2,1) DEFAULT 0,
  ADD COLUMN IF NOT EXISTS address_full TEXT,
  ADD COLUMN IF NOT EXISTS phone TEXT,
  ADD COLUMN IF NOT EXISTS website_url TEXT,
  ADD COLUMN IF NOT EXISTS opening_hours TEXT,
  ADD COLUMN IF NOT EXISTS vibe_summary TEXT;

-- Ensure business_reviews exists
CREATE TABLE IF NOT EXISTS public.business_reviews (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id UUID NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  platform TEXT NOT NULL CHECK (platform IN ('google', 'tripadvisor', 'other')),
  rating INT NOT NULL CHECK (rating >= 1 AND rating <= 5),
  review_text TEXT NOT NULL,
  author_name TEXT,
  is_positive BOOLEAN NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_business_reviews_business ON public.business_reviews(business_id);
ALTER TABLE public.business_reviews ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public read business_reviews" ON public.business_reviews;
CREATE POLICY "Public read business_reviews" ON public.business_reviews FOR SELECT USING (true);

-- Real Malta retail & notable businesses (names from public sources)
INSERT INTO public.businesses (id, name, slug, industry, description, locality, verified, is_live, live_viewer_count, cover_image_url, image_urls, google_review_count, google_rating, tripadvisor_review_count, tripadvisor_rating, address_full, phone, website_url, vibe_summary) VALUES
-- Malls & retail destinations
('a1b2c3d4-0017-4000-8000-000000000017', 'Bay Street Complex', 'bay-street-complex', 'fashion', 'Indoor mall with Adidas, Guess, Skechers, souvenir shops, VR arcade, bowling. St Julian''s hub.', 'St Julian''s', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg', '/pjazza/images/stores/restaurant.jpg'], 892, 4.2, 1104, 4.1, 'St George''s Bay, St Julian''s, Malta', '+356 2137 3737', 'https://baystreet.com.mt', 'Tourist-friendly mall. Open until 10pm. Brands + entertainment. Family vibe.'),
('a1b2c3d4-0018-4000-8000-000000000018', 'The Plaza Shopping Centre', 'the-plaza-sliema', 'fashion', 'Malta''s OG mall since 1993. Four floors: Promod, Miss Sixty, Lucy''s, Franks, food court.', 'Sliema', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg', '/pjazza/images/stores/restaurant.jpg'], 534, 4.0, 412, 3.9, 'Bisazza Street, Sliema, Malta', '+356 2133 3444', NULL, 'Classic Maltese mall. Good mix of fashion and makeup. Can feel dated but reliable.'),
('a1b2c3d4-0019-4000-8000-000000000019', 'Shoreline Mall', 'shoreline-mall-kalkara', 'fashion', '44 outlets. Homemate, Aldo, Kiko, MAC, Boost, Starbucks, Rossopomodoro. Trampolining at Gravity.', 'Kalkara', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg', '/pjazza/images/stores/restaurant.jpg'], 312, 4.3, 189, 4.2, 'Shoreline, Kalkara, Malta', NULL, NULL, 'New mall in the South. 10 min from airport. Good for beauty and homeware.'),
('a1b2c3d4-0020-4000-8000-000000000020', 'Mercury Tower Shopping', 'mercury-tower-paceville', 'fashion', 'Zaha Hadid design. 80+ fashion brands. Armani Exchange, Tommy Hilfiger. Lowes Lounge, Amorino.', 'Paceville', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg'], 445, 4.4, 278, 4.3, 'Mercury Tower, Paceville, Malta', NULL, NULL, 'Sleek, modern. Premium brands. Architecture alone worth a visit.'),
('a1b2c3d4-0021-4000-8000-000000000021', 'Arkadia Commercial Centre', 'arkadia-gozo', 'fashion', 'Gozo''s one-stop. Fashion, groceries, homeware. Independence Square area.', 'Victoria, Gozo', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg', '/pjazza/images/stores/restaurant.jpg'], 234, 4.1, 156, 4.0, 'Arkadia, Victoria, Gozo', NULL, NULL, 'Laid-back Gozo shopping. Everything under one roof. Less crowded than Malta.'),
('a1b2c3d4-0022-4000-8000-000000000022', 'Main Street Paola', 'main-street-paola', 'fashion', 'Compact complex. Accessorize, Pull & Bear, Flying Tiger, The Model Shop. South Malta convenience.', 'Paola', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg'], 98, 3.9, 67, 3.8, 'Main Street, Paola, Malta', NULL, NULL, 'Small but handy. Quick shopping break. Limited but varied.'),

-- Standalone fashion & retail
('a1b2c3d4-0023-4000-8000-000000000023', 'Charles & Ron', 'charles-ron-valletta', 'fashion', 'Malta''s top fashion label. Ready-to-wear, bags, denim. Mediterranean flair. Flagship Valletta.', 'Valletta', true, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg', '/pjazza/images/stores/restaurant.jpg'], 567, 4.7, 423, 4.6, '58D Republic Street, Valletta, Malta', '+356 2790 0592', 'https://charlesandron.com', 'Designer Maltese brand. Runway feel. Quality pieces. Pricey but special.'),
('a1b2c3d4-0024-4000-8000-000000000024', 'Soap Café', 'soap-cafe-valletta', 'beauty', 'Artisan beauty. Natural, local ingredients. Valletta shopping must-visit.', 'Valletta', false, false, 0, '/pjazza/images/stores/hair-salon.jpg', ARRAY['/pjazza/images/stores/hair-salon.jpg', '/pjazza/images/stores/fashion-boutique.jpg'], 289, 4.6, 198, 4.5, 'Republic Street, Valletta, Malta', NULL, NULL, 'Lovely local brand. Soaps, creams, gifts. Not tourist tat.'),
('a1b2c3d4-0025-4000-8000-000000000025', 'Ta'' Qali Crafts Village', 'ta-qali-crafts-village', 'tourism', 'Maltese artisans. Silver filigree, blown glass, handwoven textiles. Watch makers at work.', 'Attard', false, false, 0, '/pjazza/images/stores/gift-shop.jpg', ARRAY['/pjazza/images/stores/gift-shop.jpg', '/pjazza/images/thumb-property.jpg'], 1234, 4.5, 1876, 4.4, 'Ta'' Qali Crafts Village, Attard, Malta', NULL, NULL, 'Authentic crafts. Watch glassblowing. Souvenirs that matter. Go early.'),
('a1b2c3d4-0026-4000-8000-000000000026', 'Marsaxlokk Sunday Market', 'marsaxlokk-market', 'tourism', 'Fishing village Sunday market. Fish, produce, crafts, sweets. Scenic shopping.', 'Marsaxlokk', false, false, 0, '/pjazza/images/stores/gift-shop.jpg', ARRAY['/pjazza/images/stores/gift-shop.jpg', '/pjazza/images/thumb-food.jpg'], 2103, 4.6, 2456, 4.5, 'Marsaxlokk Harbour, Marsaxlokk, Malta', NULL, NULL, 'Sunday morning vibe. Colourful boats, fresh fish, local crafts. Tourist favourite.'),
('a1b2c3d4-0027-4000-8000-000000000027', 'Zara Malta', 'zara-the-point', 'fashion', 'Zara at The Point. Fast fashion. Sliema waterfront.', 'Sliema', false, true, 18, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg'], 687, 4.2, 434, 4.1, 'The Point Mall, Tigné, Sliema, Malta', NULL, 'https://zara.com', 'Standard Zara. Good sizes. Busy weekends. Same as everywhere but convenient.'),
('a1b2c3d4-0028-4000-8000-000000000028', 'Mango Sliema', 'mango-sliema', 'fashion', 'Mango at The Point. Women''s and men''s fashion.', 'Sliema', false, false, 0, '/pjazza/images/stores/fashion-boutique.jpg', ARRAY['/pjazza/images/stores/fashion-boutique.jpg'], 423, 4.1, 312, 4.0, 'The Point Mall, Tigné, Sliema, Malta', NULL, 'https://mango.com', 'Trendy pieces. Good for workwear. Sales worth checking.'),
