('a1b2c3d4-0017-4000-8000-000000000017', 'google', 3, 'Can get very crowded with tourists. Food court queues long.', 'Emma L.', false),
('a1b2c3d4-0017-4000-8000-000000000017', 'tripadvisor', 3, 'Parking a nightmare. Mall itself fine.', 'David R.', false),
('a1b2c3d4-0023-4000-8000-000000000023', 'google', 5, 'Stunning clothes. Maltese design at its best. Bought a dress for a wedding.', 'Claire M.', true),
('a1b2c3d4-0023-4000-8000-000000000023', 'tripadvisor', 5, 'Charles & Ron flagship is beautiful. Quality fabric. Worth the price.', 'Anna B.', true),
('a1b2c3d4-0023-4000-8000-000000000023', 'google', 3, 'Lovely but expensive. Limited sizes if you are tall.', 'Lisa P.', false),
('a1b2c3d4-0023-4000-8000-000000000023', 'tripadvisor', 4, 'Great designs. Shop can feel cramped when busy.', 'John D.', false),
('a1b2c3d4-0025-4000-8000-000000000025', 'google', 5, 'Watched glassblowing. Bought a vase. Real Maltese craft. Love it.', 'Peter K.', true),
('a1b2c3d4-0025-4000-8000-000000000025', 'tripadvisor', 5, 'Must-visit. Crafts village is unique. Bought silver filigree for mum.', 'Susan T.', true),
